import{_ as t,o as s,c as a,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Central Playwright E2E","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Central Playwright E2E | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/playwright"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Central Playwright E2E | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/playwright"}]]},"headers":[],"relativePath":"developer-guide/playwright.md","filePath":"developer-guide/playwright.md","lastUpdated":1784414421000}'),d={name:"developer-guide/playwright.md"};function o(i,e,r,l,c,p){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="central-playwright-e2e" tabindex="-1">Central Playwright E2E <a class="header-anchor" href="#central-playwright-e2e" aria-label="Permalink to &quot;Central Playwright E2E&quot;">​</a></h1><p>The Playwright suite for the <strong>Central Application</strong> lives in the Frontend repository:</p><ul><li>Guide: <a href="https://github.com/DiligentCreators/SaaS-Frontend/blob/main/docs/testing/PLAYWRIGHT.md" target="_blank" rel="noreferrer"><code>SaaS-Frontend/docs/testing/PLAYWRIGHT.md</code></a></li><li>Tests: <code>SaaS-Frontend/e2e/tests/&lt;module&gt;/</code></li><li>Shared POM / fixtures: <code>SaaS-Frontend/e2e/{pages,fixtures,helpers,utils,test-data}/</code></li><li>Config: <code>SaaS-Frontend/playwright.config.ts</code></li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Covers Platform/Core only: auth, dashboard, tenants (workspaces), users, roles, permissions matrix, modules, marketplace, billing (Billing nav + payment gateways + settings billing tab + tenant invoice/payment tabs), impersonation, settings, profile, smoke, and regression.</p><p>Does <strong>not</strong> cover Stripe Checkout or future ERP modules beyond what is listed below. Tenant Settings branding/mail coverage lives in <code>e2e/tests/settings/tenant-settings.spec.ts</code>. Tenant Users/Roles RBAC coverage lives in <code>e2e/tests/users/tenant-users.spec.ts</code> (<code>npm run test:e2e:tenant-rbac</code>). <strong>Leads</strong> product UI: <code>e2e/tests/leads/</code> (<code>npm run test:e2e:leads</code>). <strong>Tasks</strong> product UI: <code>e2e/tests/tasks/</code> (<code>npm run test:e2e:tasks</code>). <strong>Communication Templates</strong>: <code>e2e/tests/communication-templates/</code> (<code>npm run test:e2e:communication-templates</code>). Tenant suites use Playwright project <code>tenant</code>.</p><h2 id="spec-directories-independently-runnable" tabindex="-1">Spec directories (independently runnable) <a class="header-anchor" href="#spec-directories-independently-runnable" aria-label="Permalink to &quot;Spec directories (independently runnable)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Suite</th><th>Path</th><th>npm script</th></tr></thead><tbody><tr><td>Auth</td><td><code>e2e/tests/auth/</code></td><td><code>npm run test:e2e:auth</code></td></tr><tr><td>Dashboard</td><td><code>e2e/tests/dashboard/</code></td><td><code>npm run test:e2e:dashboard</code></td></tr><tr><td>Tenants / workspaces</td><td><code>e2e/tests/tenants/</code></td><td><code>npm run test:e2e:tenants</code></td></tr><tr><td>Users</td><td><code>e2e/tests/users/</code></td><td><code>npm run test:e2e:users</code> (Central) · <code>npm run test:e2e:tenant-rbac</code> (workspace Users/Roles)</td></tr><tr><td>Roles</td><td><code>e2e/tests/roles/</code></td><td><code>npm run test:e2e:roles</code></td></tr><tr><td>Permissions</td><td><code>e2e/tests/permissions/</code></td><td><code>npm run test:e2e:permissions</code></td></tr><tr><td>Modules</td><td><code>e2e/tests/modules/</code></td><td><code>npm run test:e2e:modules</code></td></tr><tr><td>Marketplace</td><td><code>e2e/tests/marketplace/</code></td><td><code>npm run test:e2e:marketplace</code></td></tr><tr><td>Billing</td><td><code>e2e/tests/billing/</code></td><td><code>npm run test:e2e:billing</code></td></tr><tr><td>Impersonation</td><td><code>e2e/tests/impersonation/</code></td><td><code>npm run test:e2e:impersonation</code></td></tr><tr><td>Settings</td><td><code>e2e/tests/settings/</code></td><td><code>npm run test:e2e:settings</code> — Central identity/flags + <code>tenant-settings.spec.ts</code> workspace branding/mail fallback (<code>npm run test:e2e:tenant-settings</code>)</td></tr><tr><td>Leads</td><td><code>e2e/tests/leads/</code></td><td><code>npm run test:e2e:leads</code></td></tr><tr><td>Tasks</td><td><code>e2e/tests/tasks/</code></td><td><code>npm run test:e2e:tasks</code></td></tr><tr><td>Communication Templates</td><td><code>e2e/tests/communication-templates/</code></td><td><code>npm run test:e2e:communication-templates</code></td></tr><tr><td>Profile</td><td><code>e2e/tests/profile/</code></td><td><code>npm run test:e2e:profile</code></td></tr><tr><td>Smoke</td><td><code>e2e/tests/smoke/</code></td><td><code>npm run test:e2e:smoke</code></td></tr><tr><td>Regression</td><td><code>e2e/tests/regression/</code></td><td><code>npm run test:e2e:regression</code></td></tr></tbody></table><p>Setup project (<code>auth.setup.ts</code>) authenticates once for chromium suites. Auth and <strong>tenant</strong> projects use empty storage and do not depend on setup.</p><h2 id="qa-status-central-stabilization" tabindex="-1">QA status (Central stabilization) <a class="header-anchor" href="#qa-status-central-stabilization" aria-label="Permalink to &quot;QA status (Central stabilization)&quot;">​</a></h2><ul><li>Full suite: <strong>48 passed</strong>, 0 skipped, 0 failed (local Chromium run).</li><li>Each module directory is executable independently via <code>npx playwright test e2e/tests/&lt;module&gt;</code> or the npm scripts above.</li><li>After module-level green runs, re-run <code>npm run test:e2e</code> before declaring Central stable.</li></ul><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><p>Playwright writes generated screenshots under:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SaaS-Frontend/docs/testing/images/</span></span>
<span class="line"><span>SaaS-Frontend/test-results/</span></span>
<span class="line"><span>SaaS-Frontend/playwright-report/</span></span></code></pre></div><p>Those paths are <strong>gitignored</strong> in Frontend and Backend — never commit e2e-generated images, videos, or traces there.</p><p>Curated documentation screenshots may be committed <strong>only</strong> in this Docs repo (<code>testing/images/…</code>) when intentionally documenting a workflow. Do not dump raw Playwright run output into Docs.</p><h2 id="quick-start" tabindex="-1">Quick start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick start&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SaaS-Frontend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.e2e.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.e2e</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e:report</span></span></code></pre></div><p>See the Frontend guide for environment variables, CI usage, debugging, and extension patterns.</p>`,19)])])}const g=t(d,[["render",o]]);export{u as __pageData,g as default};
